var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"여기서는 어떻게 불러야 할지 잘 모르겠네요.","JPN":"ここではどう呼べばいいのかわかりませんね。","ENG":"Not sure how we should refer to you here.","TWN":"不知道該怎麼稱呼這裡呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저희가 지닌 지식은 온전하지 못해서요. 사장님에 대해서도 제각각 다르게 여긴답니다.","JPN":"我々が持つ知識は完璧ではありませんので。社長のこともそれぞれ違う形で認識しているんです。","ENG":"The knowledge we have isn't complete yet. Even the views we have on you differ among us.","TWN":"畢竟我們擁有的知識還不夠完整。對老闆也有各自的看法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"어떤 호칭이 좋을까요? 사장님? 오래된 목소리? 아니면...... 관리자님?","JPN":"どう呼んでほしいですか？社長？古い声？それとも……管理者さん？","ENG":"How do you want us to call you? Boss? Old Voice? Or... Administrator?","TWN":"您喜歡怎樣的稱呼呢？老闆？老聲音？或者……管理者大人？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"후훗. 괜찮으시면 앞으로도 사장님이라고 부를게요. 다른 호칭은 왠지 거리감이 드네요.","JPN":"ふふっ。よろしければ、これからも社長と呼ばせていただきます。他の呼び名はなんだか距離感を感じますから。","ENG":"Fu fu. We'll call you Boss, if you're okay with it. All the other titles feels a bit... distant.","TWN":"呵呵，您願意的話，以後也叫您老闆吧。其他的稱呼不知怎麼，有些距離感呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"사장님께서는 많은 것을 알고 계신 것 같아요. 저희들은 그런 분을 아주 좋아한답니다.","JPN":"社長は様々なことをご存知のようですね。我々はそんな社長のような方が大好きなんです。","ENG":"You seem to know about a lot of things. And we like people with knowledge.","TWN":"老闆似乎知道很多事情。當然我們非常喜歡這種人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그렇다고 너무 경계하지는 마세요.","JPN":"だからといって、警戒はしないでください。","ENG":"Oh, there's no need for you to get defensive.","TWN":"話是這麼說，但請不要對我們太過防備。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"현장이라고 하나요? 그곳에 가면 마음껏 허기를 채울 수 있거든요.","JPN":"現場と言うのでしょうか？あそこに行けば思う存分、飢えを満たすことができます。","ENG":"We can satisfy our hunger while we're out in the field. That's what you call it, right? The field.","TWN":"您叫那裡現場嗎？只要去那裡，就能盡情地滿足飢餓感呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님은 적당히 먹으라고 하시지만...... 지식을 채우려는 욕구는 억누르기가 무척 어렵답니다.","JPN":"レジーナ様はほどほどにしろって仰ってますが……知識を満たしたいという欲求は抑えきれません。","ENG":"Miss Regina tells us that we shouldn't overdo it, but this desire for knowledge is very hard to contain.","TWN":"雖然蕾佳娜大人說吃東西要適可而止……但要壓抑填滿知識的欲求，是很困難的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그리고 무엇보다, 사장님께서 정성껏 차려 주시는 만찬을 거절하는 건 예의가 아니니까요.","JPN":"そして何より、社長が丁寧に用意してくださる晩餐を断るのは礼儀に反しますので。","ENG":"And besides, it wouldn't be polite for us to decline the great feast you've prepared for us, would it?","TWN":"而且最重要的是，拒絕老闆精心為我們準備的晚餐，是有失禮儀的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그러고 보니 사장님은 침식체를 드셔 보신 적이 없겠네요.","JPN":"そういえば、社長は侵食体を召し上がったことはありませんよね。","ENG":"Come to think of it, you haven't eaten a Corrupted Object, have you?","TWN":"這麼說來，老闆好像還沒有吃過侵蝕體呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저번에 현장에서 마침 아껴 놓은 게 있답니다. 사장님께 나눠 드릴게요.","JPN":"先日、現場で食べずに置いておいたものがあります。社長におすそ分けしましょう。","ENG":"We spared some from the scene we were in the other day. We'll gladly share it with you.","TWN":"這裡正好有在上次現場珍藏起來的東西，就分給老闆您吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"......정말요? 저희만 먹어도 괜찮을까요?","JPN":"……本当ですか？我々が全部食べてもよろしいのですか？","ENG":"Really? Are you sure you don't want us to share?","TWN":"……真的嗎？我們自己吃掉也沒關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"기뻐라...... 배려해 주셔서 고마워요. 실은 막 허기가 지기 시작하던 참이었거든요.","JPN":"嬉しい……ご配慮いただきありがとうございます。実はちょうどお腹が空き始めました。","ENG":"How sweet. Thank you for your consideration. We were just getting hungry, actually.","TWN":"好高興……謝謝您的關心。事實上，我們的飢餓感又沒由來地開始了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"역시 사장님 같은 분과는 헤어지고 싶지 않아요.","JPN":"やはり社長のような方と別れたくありません。","ENG":"We'd really hate to part ways with someone like you.","TWN":"我們果然不想和老闆這樣的人分開啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"앞으로도 오래오래...... 잘 부탁드릴게요. 사장님.","JPN":"これからも末永く……よろしくお願いしますね。社長。","ENG":"We want to stay near you for as long as we can, Boss.","TWN":"以後也要長長久久……承蒙您的關照了。老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};